const body = $json.body || $json;

// Extract all lookup IDs from payload
const items = body.items || [];
const itemIds = [...new Set(items.map(i => i.item_id || i.id).filter(Boolean))];

const modIds = [];
const groupIds = [];

items.forEach(item => {
  (item.modifiers || []).forEach(mod => {
    if (mod.mod_id || mod.code) modIds.push(mod.mod_id || mod.code);
    if (mod.group_id || mod.group) groupIds.push(mod.group_id || mod.group);
  });
});

return {
  json: {
    body,
    lookup_item_ids: itemIds,
    lookup_mod_ids: [...new Set(modIds)],
    lookup_group_ids: [...new Set(groupIds)]
  }
};

const extractData = $('Extract Lookup IDs').first().json;
const body = extractData.body;
const items = body.items || [];

// DB lookup results
const dbItems = {};
($('DB: Lookup Items').all()[0]?.json || []).forEach(row => {
  dbItems[row.item_id] = row;
});

const dbMods = {};
($('DB: Lookup Modifiers').all()[0]?.json || []).forEach(row => {
  dbMods[row.mod_id] = row;
});

const dbGroups = {};
($('DB: Lookup Groups').all()[0]?.json || []).forEach(row => {
  if (!dbGroups[row.item_id]) dbGroups[row.item_id] = {};
  dbGroups[row.item_id][row.group_id] = row;
});

const errors = [];
const validatedItems = [];
let subtotalCents = 0;
const comboSides = [];

items.forEach((item, idx) => {
  const itemId = item.item_id || item.id;
  const qty = Math.max(1, parseInt(item.qty) || 1);

  // Validate item
  const dbItem = dbItems[itemId];
  if (!dbItem) {
    errors.push(`Item ${itemId} not found`);
    return;
  }
  if (!dbItem.active) {
    errors.push(`Item ${itemId} is inactive`);
    return;
  }

  const basePrice = dbItem.base_price_cents;
  let modifiersTotal = 0;
  const validatedModifiers = [];
  const groupCounts = {};

  // Process modifiers
  (item.modifiers || []).forEach(mod => {
    const modId = mod.mod_id || mod.code;
    const groupId = mod.group_id || mod.group;
    const dbMod = dbMods[modId];

    if (!dbMod) {
      errors.push(`Modifier ${modId} not found`);
      return;
    }
    if (!dbMod.active) {
      errors.push(`Modifier ${modId} is inactive`);
      return;
    }
    if (dbMod.group_id !== groupId) {
      errors.push(`Modifier ${modId} group mismatch: expected ${dbMod.group_id}, got ${groupId}`);
      return;
    }

    // Check group ownership
    const itemGroups = dbGroups[itemId] || {};
    if (!itemGroups[groupId]) {
      errors.push(`Group ${groupId} not valid for item ${itemId}`);
      return;
    }

    // Count per group
    groupCounts[groupId] = (groupCounts[groupId] || 0) + 1;

    // Handle combo separately
    if (modId.endsWith('_COMBO_FRIES') || modId.endsWith('_COMBO_SALAD')) {
      const sideName = modId.endsWith('_COMBO_FRIES') ? 'Combo plain fries' : 'Combo side salad';
      comboSides.push({
        name: sideName,
        quantity: qty,
        amount_cents: dbMod.price_delta_cents,
        parent_item_id: itemId,
        source_mod_id: modId
      });
      validatedModifiers.push({
        mod_id: modId,
        group_id: groupId,
        mod_name: dbMod.mod_name,
        price_delta_cents: 0,  // Display only
        is_combo: true
      });
    } else {
      modifiersTotal += dbMod.price_delta_cents;
      validatedModifiers.push({
        mod_id: modId,
        group_id: groupId,
        mod_name: dbMod.mod_name,
        price_delta_cents: dbMod.price_delta_cents
      });
    }
  });

  // Check group min/max
  const itemGroups = dbGroups[itemId] || {};
  Object.values(itemGroups).forEach(group => {
    const count = groupCounts[group.group_id] || 0;
    if (group.min_select > 0 && count < group.min_select) {
      errors.push(`${item.name} requires ${group.min_select} selection(s) for ${group.group_label}`);
    }
    if (count > group.max_select) {
      errors.push(`${item.name} exceeds max ${group.max_select} for ${group.group_label}`);
    }
  });

  const unitTotal = basePrice + modifiersTotal;
  const itemTotal = unitTotal * qty;
  subtotalCents += itemTotal;

  validatedItems.push({
    item_id: itemId,
    name: dbItem.name,
    quantity: qty,
    base_price_cents: basePrice,
    modifiers: validatedModifiers,
    unit_total_cents: unitTotal,
    line_total_cents: itemTotal
  });
});

// Calculate tax
const TAX_RATE = 0.0952;
const taxCents = Math.round(subtotalCents * TAX_RATE);
const finalTotal = subtotalCents + taxCents;

// Check frontend mismatch (diagnostic only)
const frontendTotal = body.frontend_total_cents || body.subtotal_cents || 0;
const mismatch = frontendTotal > 0 && Math.abs(frontendTotal - subtotalCents) > 1;

// Build Square line items
const squareLineItems = validatedItems.map(item => ({
  name: item.name,
  quantity: String(item.quantity),
  base_price_money: {
    amount: item.unit_total_cents,
    currency: 'USD'
  },
  modifiers: item.modifiers
    .filter(m => !m.is_combo)
    .map(m => ({
      name: m.mod_name,
      base_price_money: { amount: 0, currency: 'USD' }
    }))
}));

// Add combo sides as separate line items
comboSides.forEach(side => {
  squareLineItems.push({
    name: side.name,
    quantity: String(side.quantity),
    base_price_money: {
      amount: side.amount_cents,
      currency: 'USD'
    }
  });
});

// Add tax as line item
squareLineItems.push({
  name: 'Sales Tax (9.52%)',
  quantity: '1',
  base_price_money: {
    amount: taxCents,
    currency: 'USD'
  }
});

// Order ID
const orderId = 'UTO-' + Date.now() + '-' + Math.random().toString(36).substr(2, 5).toUpperCase();

return {
  json: {
    ok: errors.length === 0,
    errors,
    customer: body.customer || {},
    items: validatedItems,
    combo_sides: comboSides,
    square_line_items: squareLineItems,
    subtotal_cents: subtotalCents,
    tax_cents: taxCents,
    total_cents: finalTotal,
    frontend_mismatch: mismatch,
    frontend_subtotal: frontendTotal,
    order_id: orderId,
    cart_id: orderId,
    pickup_time: body.pickup_time || 'ASAP',
    notes: body.notes || ''
  }
};

const validated = $('Validate & Calculate').first().json;

if (!validated.ok) {
  return {
    json: {
      status: 400,
      error: 'Validation failed',
      details: validated.errors
    }
  };
}

return validated;

